  1→import { contract, importSnapshotSchema } from "@chat-exporter/shared";
  2→import { implement, ORPCError } from "@orpc/server";
  3→
  4→import { databasePath, withTransaction } from "../db/client.js";
  5→import {
  6→  AgentUnavailableError,
  7→  runAgentTurn,
  8→} from "../lib/adjustment-agent.js";
  9→import {
 10→  appendAdjustmentMessage,
 11→  createAdjustmentSession,
 12→  createFormatRuleDirect,
 13→  demoteRuleToLocal,
 14→  disableFormatRule,
 15→  discardAdjustmentSession,
 16→  getAdjustmentMetrics,
 17→  getAdjustmentSessionDetail,
 18→  listAdjustmentSessions,
 19→  listFormatRules,
 20→  markSessionApplied,
 21→  promoteRuleToProfile,
 22→  recordAdjustmentEvent,
 23→  reopenAdjustmentSession,
 24→  updateFormatRuleEffect,
 25→} from "../lib/adjustment-repository.js";
 26→import {
 27→  listDeletions,
 28→  restoreMessage,
 29→  softDeleteMessage,
 30→  softDeleteRound,
 31→} from "../lib/delete-repository.js";
 32→import { getPersistedImportSnapshot } from "../lib/import-repository.js";
 33→import {
 34→  createImportJob,
 35→  deleteImportJob,
 36→  getImportJob,
 37→  listImportJobs,
 38→  runImportJob,
 39→} from "../lib/import-store.js";
 40→
 41→export const RAW_HTML_PREVIEW_LENGTH = 16_000;
 42→
 43→function isSupportedChatGptShareLink(urlString: string) {
 44→  let url: URL;
 45→  try {
 46→    url = new URL(urlString);
 47→  } catch {
 48→    return false;
 49→  }
 50→  return url.hostname === "chatgpt.com" && url.pathname.startsWith("/share/");
 51→}
 52→
 53→const os = implement(contract);
 54→
 55→export const router = os.router({
 56→  imports: {
 57→    list: os.imports.list.handler(({ input }) => {
 58→      return listImportJobs(input);
 59→    }),
 60→
 61→    delete: os.imports.delete.handler(({ input }) => {
 62→      const job = getImportJob(input.id);
 63→      if (!job) {
 64→        throw new ORPCError("NOT_FOUND", {
 65→          message: "Import nicht gefunden.",
 66→        });
 67→      }
 68→      const deleted = deleteImportJob(input.id);
 69→      return { deleted };
 70→    }),
 71→
 72→    create: os.imports.create.handler(({ input }) => {
 73→      if (!isSupportedChatGptShareLink(input.url)) {
 74→        throw new ORPCError("BAD_REQUEST", {
 75→          message:
 76→            "Dieser erste Stand akzeptiert nur öffentliche ChatGPT-Share-Links.",
 77→        });
 78→      }
 79→
 80→      const job = createImportJob(input);
 81→      void runImportJob(job.id);
 82→      return job;
 83→    }),
 84→
 85→    get: os.imports.get.handler(({ input }) => {
 86→      const job = getImportJob(input.id);
 87→
 88→      if (!job) {
 89→        throw new ORPCError("NOT_FOUND", {
 90→          message: "Import nicht gefunden.",
 91→        });
 92→      }
 93→
 94→      return job;
 95→    }),
 96→
 97→    snapshot: os.imports.snapshot.handler(({ input }) => {
 98→      const snapshot = getPersistedImportSnapshot(input.id);
 99→
100→      if (!snapshot) {
101→        throw new ORPCError("NOT_FOUND", {
102→          message: "Import-Snapshot nicht gefunden.",
103→        });
104→      }
105→
106→      const rawHtmlPreview = snapshot.rawHtml.slice(0, RAW_HTML_PREVIEW_LENGTH);
107→
108→      return importSnapshotSchema.parse({
109→        importId: snapshot.importId,
110→        sourceUrl: snapshot.sourceUrl,
111→        finalUrl: snapshot.finalUrl,
112→        fetchedAt: snapshot.fetchedAt,
113→        pageTitle: snapshot.pageTitle,
114→        rawHtmlBytes: Buffer.byteLength(snapshot.rawHtml, "utf8"),
115→        rawHtmlPreview,
116→        rawHtmlTruncated: snapshot.rawHtml.length > rawHtmlPreview.length,
117→        normalizedPayload: snapshot.normalizedPayload,
118→        fetchMetadata: snapshot.fetchMetadata,
119→      });
120→    }),
121→
122→    rawHtml: os.imports.rawHtml.handler(({ input }) => {
123→      const snapshot = getPersistedImportSnapshot(input.id);
124→
125→      if (!snapshot) {
126→        throw new ORPCError("NOT_FOUND", {
127→          message: "Import-Snapshot nicht gefunden.",
128→        });
129→      }
130→
131→      return snapshot.rawHtml;
132→    }),
133→
134→    // Design-Entscheidung: Dieser Endpoint liefert absichtlich rohe, unveränderte
135→    // Artefakte ohne angewendete Format-Rules. Client-seitiger Markdown-Download
136→    // verwendet stattdessen `displayedMarkdown` (mit `applyMarkdownRules` inkl.
137→    // format_profile-Rules). Änderungen hier dürfen diese Trennung nicht aufheben.
138→    exportArtifact: os.imports.exportArtifact.handler(({ input }) => {
139→      const job = getImportJob(input.id);
140→
141→      if (!job || !job.artifacts) {
142→        throw new ORPCError("NOT_FOUND", {
143→          message: "Export-Artefakt nicht gefunden.",
144→        });
145→      }
146→
147→      switch (input.format) {
148→        case "markdown":
149→          return job.artifacts.markdown;
150→        case "handover":
151→          return job.artifacts.handover;
152→        case "json":
153→          return job.artifacts.json;
154→        default:
155→          throw new ORPCError("BAD_REQUEST", {
156→            message: "Nicht unterstütztes Exportformat.",
157→          });
158→      }
159→    }),
160→  },
161→
162→  adjustments: {
163→    listSessions: os.adjustments.listSessions.handler(({ input }) => {
164→      const job = getImportJob(input.importId);
165→
166→      if (!job) {
167→        throw new ORPCError("NOT_FOUND", {
168→          message: "Import nicht gefunden.",
169→        });
170→      }
171→
172→      return listAdjustmentSessions(input.importId, input.format);
173→    }),
174→
175→    createSession: os.adjustments.createSession.handler(({ input }) => {
176→      const job = getImportJob(input.importId);
177→
178→      if (!job) {
179→        throw new ORPCError("NOT_FOUND", {
180→          message: "Import nicht gefunden.",
181→        });
182→      }
183→
184→      const { session } = createAdjustmentSession({
185→        importId: input.importId,
186→        selection: input.selection,
187→        targetFormat: input.targetFormat,
188→      });
189→      const detail = getAdjustmentSessionDetail(session.id);
190→
191→      if (!detail) {
192→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
193→          message: "Anpassungssession konnte nicht geladen werden.",
194→        });
195→      }
196→
197→      return detail;
198→    }),
199→
200→    getSession: os.adjustments.getSession.handler(({ input }) => {
201→      const detail = getAdjustmentSessionDetail(input.id);
202→
203→      if (!detail) {
204→        throw new ORPCError("NOT_FOUND", {
205→          message: "Anpassungssession nicht gefunden.",
206→        });
207→      }
208→
209→      return detail;
210→    }),
211→
212→    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
213→      const detail = getAdjustmentSessionDetail(input.sessionId);
214→
215→      if (!detail) {
216→        throw new ORPCError("NOT_FOUND", {
217→          message: "Anpassungssession nicht gefunden.",
218→        });
219→      }
220→
221→      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
222→      const latestDetail = withTransaction(() => {
223→        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
224→
225→        if (!freshDetail) {
226→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
227→            message: "Anpassungssession konnte nicht neu geladen werden.",
228→          });
229→        }
230→
231→        if (freshDetail.session.status === "applied") {
232→          reopenAdjustmentSession(input.sessionId);
233→        }
234→
235→        appendAdjustmentMessage(input.sessionId, "user", input.content);
236→
237→        const reloaded = getAdjustmentSessionDetail(input.sessionId);
238→
239→        if (!reloaded) {
240→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
241→            message: "Anpassungssession konnte nicht neu geladen werden.",
242→          });
243→        }
244→
245→        return reloaded;
246→      });
247→
248→      const activeRules = listFormatRules(
249→        detail.session.importId,
250→        detail.session.targetFormat,
251→      ).filter((rule: { status: string }) => rule.status === "active");
252→
253→      // Phase 2 — no wrapper: async AI call
254→      try {
255→        const job = getImportJob(detail.session.importId);
256→        const result = await runAgentTurn({
257→          sessionDetail: latestDetail,
258→          activeRules,
259→          job,
260→          callbacks: {
261→            onCreateRule: async ({ selector, effect, description }) => {
262→              const rule = createFormatRuleDirect({
263→                importId: latestDetail.session.importId,
264→                targetFormat: latestDetail.session.targetFormat,
265→                selector,
266→                effect: {
267→                  type: "custom_style" as const,
268→                  ...effect,
269→                  description,
270→                },
271→                instruction: description,
272→                sourceSessionId: input.sessionId,
273→              });
274→              return { ruleId: rule.id };
275→            },
276→            onUpdateRule: async ({ ruleId, effect, description }) => {
277→              updateFormatRuleEffect(
278→                ruleId,
279→                { type: "custom_style" as const, ...effect, description },
280→                description,
281→              );
282→            },
283→            onDeleteRule: async (ruleId) => {
284→              disableFormatRule(ruleId, latestDetail.session.importId);
285→            },
286→          },
287→        });
288→
289→        // Phase 3 — persist assistant message + events
290→        withTransaction(() => {
291→          appendAdjustmentMessage(
292→            input.sessionId,
293→            "assistant",
294→            result.assistantMessage,
295→          );
296→
297→          for (const action of result.actions) {
298→            recordAdjustmentEvent({
299→              importId: latestDetail.session.importId,
300→              ruleId: action.ruleId,
301→              sessionId: input.sessionId,
302→              targetFormat: latestDetail.session.targetFormat,
303→              type:
304→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
305→            });
306→          }
307→
308→          if (result.actions.length > 0) {
309→            markSessionApplied(input.sessionId);
310→          } else {
311→            recordAdjustmentEvent({
312→              importId: latestDetail.session.importId,
313→              sessionId: input.sessionId,
314→              targetFormat: latestDetail.session.targetFormat,
315→              type: "clarification_requested",
316→            });
317→          }
318→        });
319→      } catch (error) {
320→        if (error instanceof AgentUnavailableError) {
321→          throw new ORPCError("SERVICE_UNAVAILABLE", {
322→            message: error.message,
323→          });
324→        }
325→        if (error instanceof DOMException && error.name === "TimeoutError") {
326→          throw new ORPCError("GATEWAY_TIMEOUT", {
327→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
328→          });
329→        }
330→        throw new ORPCError("BAD_REQUEST", {
331→          message:
332→            error instanceof Error
333→              ? error.message
334→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
335→        });
336→      }
337→
338→      const nextDetail = getAdjustmentSessionDetail(input.sessionId);
339→
340→      if (!nextDetail) {
341→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
342→          message: "Anpassungssession konnte nicht neu geladen werden.",
343→        });
344→      }
345→
346→      return nextDetail;
347→    }),
348→
349→    discard: os.adjustments.discard.handler(({ input }) => {
350→      try {
351→        return discardAdjustmentSession(input.sessionId);
352→      } catch (error) {
353→        throw new ORPCError("BAD_REQUEST", {
354→          message:
355→            error instanceof Error
356→              ? error.message
357→              : "Anpassungssession konnte nicht verworfen werden.",
358→        });
359→      }
360→    }),
361→
362→    metrics: os.adjustments.metrics.handler(({ input }) => {
363→      return getAdjustmentMetrics(input.importId, input.format);
364→    }),
365→  },
366→
367→  rules: {
368→    list: os.rules.list.handler(({ input }) => {
369→      return listFormatRules(input.importId, input.format);
370→    }),
371→
372→    disable: os.rules.disable.handler(({ input }) => {
373→      try {
374→        return disableFormatRule(input.id, input.importId);
375→      } catch (error) {
376→        throw new ORPCError("BAD_REQUEST", {
377→          message:
378→            error instanceof Error
379→              ? error.message
380→              : "Formatregel konnte nicht deaktiviert werden.",
381→        });
382→      }
383→    }),
384→
385→    promote: os.rules.promote.handler(({ input }) => {
386→      try {
387→        return promoteRuleToProfile(input.id);
388→      } catch (error) {
389→        throw new ORPCError("BAD_REQUEST", {
390→          message:
391→            error instanceof Error
392→              ? error.message
393→              : "Formatregel konnte nicht zum Profil befördert werden.",
394→        });
395→      }
396→    }),
397→
398→    demote: os.rules.demote.handler(({ input }) => {
399→      try {
400→        return demoteRuleToLocal(input.id, input.importId);
401→      } catch (error) {
402→        throw new ORPCError("BAD_REQUEST", {
403→          message:
404→            error instanceof Error
405→              ? error.message
406→              : "Formatregel konnte nicht zurückgestuft werden.",
407→        });
408→      }
409→    }),
410→  },
411→
412→  deletions: {
413→    list: os.deletions.list.handler(({ input }) => {
414→      return listDeletions(input.importId);
415→    }),
416→
417→    delete: os.deletions.delete.handler(({ input }) => {
418→      try {
419→        const deletion = withTransaction(() => {
420→          const result = softDeleteMessage(
421→            input.importId,
422→            input.messageId,
423→            input.reason,
424→          );
425→          recordAdjustmentEvent({
426→            importId: input.importId,
427→            targetFormat: "reader",
428→            type: "message_deleted",
429→            payload: { messageId: input.messageId },
430→          });
431→          return result;
432→        });
433→        return deletion;
434→      } catch (error) {
435→        throw new ORPCError("BAD_REQUEST", {
436→          message:
437→            error instanceof Error
438→              ? error.message
439→              : "Message konnte nicht gelöscht werden.",
440→        });
441→      }
442→    }),
443→
444→    deleteRound: os.deletions.deleteRound.handler(({ input }) => {
445→      try {
446→        const deletions = withTransaction(() => {
